import{_ as t,c as e,o as r,aN as o}from"./chunks/framework.BRm39z_l.js";const h=JSON.parse('{"title":"锁","description":"","frontmatter":{},"headers":[],"relativePath":"java/03.Java并发/02. 锁.md","filePath":"java/03.Java并发/02. 锁.md"}'),n={name:"java/03.Java并发/02. 锁.md"};function s(i,a,l,p,_,d){return r(),e("div",null,a[0]||(a[0]=[o('<h1 id="锁" tabindex="-1">锁 <a class="header-anchor" href="#锁" aria-label="Permalink to &quot;锁&quot;">​</a></h1><h2 id="线程死锁了解吗" tabindex="-1">线程死锁了解吗？ <a class="header-anchor" href="#线程死锁了解吗" aria-label="Permalink to &quot;线程死锁了解吗？&quot;">​</a></h2><p>死锁发生在多个线程相互等待对方释放锁时。比如说线程 1 持有锁 R1，等待锁 R2；线程 2 持有锁 R2，等待锁 R1。</p><ol><li><p><strong>互斥条件</strong>：资源同一时间只能被一个进程使用。</p></li><li><p><strong>请求与保持</strong>： 进程已经持有资源，又去请求别的资源，且不释放已占有的。</p></li><li><p><strong>不可抢占</strong>：资源只能由持有它的进程主动释放，不能被强行抢走。</p></li><li><p><strong>循环等待</strong>：进程之间形成一个<strong>环形等待链</strong>：A 等 B，B 等 C，C 等 A。</p></li></ol><h2 id="该如何避免死锁" tabindex="-1">该如何避免死锁 <a class="header-anchor" href="#该如何避免死锁" aria-label="Permalink to &quot;该如何避免死锁&quot;">​</a></h2><p>第一，所有线程都按照固定的顺序来申请资源。例如，先申请 R1 再申请 R2。</p><p>第二，如果线程发现无法获取某个资源，可以先释放已经持有的资源，重新尝试申请。</p>',7)]))}const m=t(n,[["render",s]]);export{h as __pageData,m as default};
